				}
				if err := sleepOrWake(ctx, delay, runtime.WakeCh); err != nil {
					if exitReason == "" {
						applyStop(work.StopInput{ContextErr: err})
					}
					return result, err
				}
				probeAt := now().UTC()
				setServerUnavailableState(probeAt)
				healthy := false
				var probeErr error
				if runtime.ServerHealthProbe != nil {
